INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Proposal templates$q$, $q$250+ pre-built, editable templates across industries like web design, marketing, and consulting.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$E-signatures$q$, $q$Legally binding electronic signatures built directly into every proposal.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$In-document payments$q$, $q$Collect deposits or full payment at signature via Stripe, PayPal, or GoCardless.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Interactive pricing tables$q$, $q$Clients can select optional add-ons and see the price update live before signing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Proposal analytics$q$, $q$See when a proposal is opened, time spent per page, and signature timestamps.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Content library$q$, $q$Reusable text blocks, case studies, and pricing modules for consistent messaging.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$CRM and API integrations$q$, $q$Connects to HubSpot, Salesforce, Pipedrive, Zapier, and roughly 50 other tools on Premium+ plans.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Fast to produce a polished, on-brand proposal without design skills$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Signature and payment collection happen in the same document, shortening the sales cycle$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Detailed view/open analytics help reps prioritize follow-up$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Bootstrapped, founder-led company with a long operating history and no VC pressure to pivot$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$No permanently free plan; entry tier caps both users and monthly sends$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$CRM integrations and API/Zapier access are locked behind the Premium tier and above$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Not a general-purpose e-signature or contract tool, so it's a poor fit outside sales proposals$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Custom template design is a separate paid service rather than included$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Is there a free version of Better Proposals?$q$, $q$No, Better Proposals does not offer a permanently free plan; all tiers are paid subscriptions, though annual billing lowers the monthly cost.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Can clients pay directly inside a Better Proposals document?$q$, $q$Yes, proposals can include native payment collection through Stripe, PayPal, or GoCardless so clients can pay at the moment they sign.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Does Better Proposals support electronic signatures?$q$, $q$Yes, every plan includes legally binding e-signatures built into the proposal itself.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$What is the difference between the Starter and Premium plans?$q$, $q$Starter is limited to 1 user and 10 sent documents per month; Premium removes the user cap, raises the document limit, and adds a custom domain, CRM integrations, and API/Zapier access.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Does Better Proposals integrate with a CRM?$q$, $q$Yes, on Premium and Enterprise plans it connects to CRMs like HubSpot, Salesforce, and Pipedrive, plus about 50 other tools via native integrations or Zapier.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Agency proposal creation$q$, $q$Marketing and web design agencies use templates and a content library to send consistent, branded proposals quickly.$q$, $q$Marketing and web design agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Freelance client pitches$q$, $q$Freelancers replace manually formatted Word/PDF proposals with trackable, signable web documents.$q$, $q$Freelancers and independent consultants$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$B2B sales closing$q$, $q$Sales teams use pricing tables and payment collection to shorten the time between proposal and signed, paid deal.$q$, $q$B2B sales teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Starter$q$, $q$$19/user/month$q$, $q$monthly (annual billing discounted)$q$, NULL, $q$["1 user","10 documents/month","E-signatures","Interactive pricing tables","Payment integrations","Content library"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Premium$q$, $q$$29/user/month$q$, $q$monthly (annual billing discounted)$q$, NULL, $q$["Unlimited users","50 documents/month","Custom domain","CRM integrations","API/Zapier access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Enterprise$q$, $q$$49/user/month$q$, $q$monthly (annual billing discounted)$q$, NULL, $q$["Unlimited users and documents","Content locking","Simultaneous editing","Inline commenting","Manager approvals"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Better Proposals is a proposal creation and e-signature platform built for freelancers, agencies, and B2B sales teams. Founded by Adam Hempenstall and launched publicly in 2015, the London-based company has grown as a bootstrapped, VC-free business focused on one narrow job: turning a written scope of work into a polished, trackable, signable web document in minutes instead of hours.$q$, $q$Rather than being a broad document-workflow suite, Better Proposals focuses specifically on the proposal-to-signature-to-payment moment in the sales process, with proposal-specific analytics like page-by-page view time and signature timestamps.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users start from one of 250+ industry-specific templates and customize copy, pricing tables, and branding without design skills. Interactive pricing tables let recipients select optional add-ons before approving, and legally binding e-signatures close the deal on the same page.$q$, $q$Built-in payment collection (via Stripe, PayPal, or GoCardless) lets clients pay a deposit or full invoice at the moment they sign. Real-time notifications and analytics show exactly when a proposal is opened, which sections get read, and when it's signed, helping reps time their follow-ups.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Better Proposals uses per-user, tiered pricing with no permanently free plan. Starter is the entry tier for solo users with capped monthly sends; Premium removes the user cap and adds CRM integrations, API/Zapier access, and a custom domain; Enterprise adds collaboration and approval controls for larger teams. Annual billing is discounted versus monthly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Uptime monitoring$q$, $q$Multi-location checks for websites, APIs, SSL, domains, and common network protocols with sub-3-minute intervals.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Log management$q$, $q$Ingest and query structured logs and traces via SQL, PromQL, or a drag-and-drop query builder.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$VRL data transformation$q$, $q$Reshape and enrich incoming telemetry using Vector Remap Language pipelines.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Incident & on-call management$q$, $q$Escalation policies, on-call scheduling, incident timelines, and AI-generated post-mortems.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Status pages$q$, $q$Public or private status pages that reflect live monitor and incident data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Multi-channel alerting$q$, $q$Slack, email, SMS, and phone call notifications for outages and incidents.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Free tier is usable for real projects, not just a trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Combines monitoring, logging, and incident response in one product and one bill$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Consumption-based telemetry pricing can be cheaper than flat-rate legacy observability vendors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Fast setup with SQL/PromQL/drag-and-drop querying options$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Pricing structure is granular (role + monitors + telemetry bundles), which can be harder to estimate upfront than a flat per-seat price$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Log/trace retention on the free tier is short (3 days)$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Advanced incident workflows and extra monitors require add-on charges$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Younger company (founded 2021) with a smaller track record than legacy observability vendors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Is Better Stack free to use?$q$, $q$Yes, Better Stack has a free tier with 10 monitors and heartbeats, 1 status page, and several days of log/trace retention, suitable for personal or small projects.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$What does Better Stack monitor?$q$, $q$It monitors websites, APIs, ping, SSL certificates, domain expiration, and protocols like POP3, IMAP, SMTP, and DNS, alongside ingesting application logs, metrics, and traces.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Does Better Stack include on-call and incident management?$q$, $q$Yes, paid 'Responder' seats add on-call scheduling, escalation policies, incident timelines, and AI-assisted post-mortems.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$How is Better Stack priced?$q$, $q$Pricing combines a free base tier, per-responder charges for incident/on-call features, and usage-based telemetry bundles (Nano to Tera) priced by data volume and retention.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Where is Better Stack based?$q$, $q$Better Stack was founded in 2021 and is headquartered in Prague, Czech Republic.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Consolidating observability tools$q$, $q$Engineering teams replace separate uptime, logging, and on-call vendors with one integrated platform.$q$, $q$Engineering and DevOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Cost-sensitive log management$q$, $q$Teams outgrowing free logging tiers elsewhere move to Better Stack's usage-based telemetry pricing to control costs at scale.$q$, $q$Startups and cost-conscious engineering orgs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Public status communication$q$, $q$Teams stand up branded status pages tied directly to live monitor data to communicate uptime to customers.$q$, $q$SaaS companies and API providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["10 monitors & heartbeats","1 status page","Slack & email alerts","3 GB log/trace/event retention (3 days)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Responder$q$, $q$$29-34/month$q$, $q$monthly or annual$q$, NULL, $q$["Uptime + telemetry access","On-call scheduling","Incident timelines"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$Telemetry (Nano-Tera bundles)$q$, $q$$30-$1,750/month$q$, $q$monthly or annual$q$, NULL, $q$["30-day retention","40 GB to 700 GB data allocation across logs, traces, and metrics"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Better Stack is an observability platform founded in 2021 and headquartered in Prague, Czech Republic. It merges uptime monitoring, log and trace management, and incident/on-call response into a single product, targeting engineering teams who currently stitch together several separate tools (a status-page vendor, a logging vendor, and a PagerDuty-style on-call tool) and want one bill and one dashboard instead.$q$, $q$The company markets itself heavily on cost compared with incumbents like Datadog, claiming order-of-magnitude savings at similar data volumes, alongside a genuinely usable free tier for small projects and side projects.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Uptime monitoring covers websites, APIs, SSL certificates, domain expiration, and common network protocols from multiple regions, with SMS/phone/Slack/email alerting. The logs and traces module supports SQL, PromQL, and drag-and-drop querying, plus VRL-based transformation of incoming data.$q$, $q$Incident management adds on-call scheduling, escalation policies, incident timelines, and AI-assisted post-mortems, tying directly back into the monitoring and logging data so incidents are investigated in the same platform where they were detected. Customizable public or private status pages round out the customer-communication side.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Better Stack uses a free tier plus consumption- and role-based paid pricing rather than one flat plan. The free tier is usable for real small projects (10 monitors, 1 status page, several days of log retention). Paid usage adds a per-responder charge for on-call/incident features and separate usage-based telemetry bundles (Nano through Tera) priced by data volume and retention, with an annual billing discount across the board.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ff22411-f622-417d-9bda-6ec2bdfd971c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$White-label Design Studio$q$, $q$Visual control of layout, color, and typography, hosted on the brand's own custom domain.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Pre-built community apps$q$, $q$Q&A forums, discussion boards, event calendars, polls, and knowledge base articles.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Ask AI & federated search$q$, $q$AI-assisted answers and cross-content search available on Growth and Premium plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Moderation & analytics$q$, $q$Member and content moderation tools with basic or advanced (Growth+) analytics.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$App Store integrations$q$, $q$Native connections to Zendesk, Intercom, Slack, Mailchimp, Google Analytics, Mixpanel, and Amplitude.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$API, webhooks & OAuth2$q$, $q$Programmatic access and single sign-on available from the Growth tier upward.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Enterprise security$q$, $q$SAML SSO, audit logs, and a 99.9% SLA on the Premium tier.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Fully white-labeled, custom-domain community that doesn't look like third-party forum software$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Broad integration set with common support and analytics tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$AI-assisted search/answers available on the mid-tier plan$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Enterprise-grade security options (SAML, audit log, SLA) at the top tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$No free plan; entry pricing at $399/month prices out very small teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$API/webhook access and branding removal require the $1,500/month Growth tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Member caps mean growing communities may face overage costs or forced upgrades$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Premium tier pricing is not public and requires a sales conversation$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Does Bettermode have a free plan?$q$, $q$No, Bettermode has no free tier; its Starter plan begins at $399/month, though a free trial is available.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Can I use my own domain with Bettermode?$q$, $q$Yes, custom domain hosting is included on every plan, including Starter.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Does Bettermode include AI features?$q$, $q$Yes, Ask AI and federated search are included starting on the Growth ($1,500/month) plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$What integrations does Bettermode support?$q$, $q$It natively integrates with tools like Zendesk, Intercom, Slack, Mailchimp, Google Analytics, Mixpanel, and Amplitude, with more available via its App Store and Zapier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Is Bettermode suitable for small businesses?$q$, $q$It's generally better suited to mid-market and enterprise SaaS companies given its $399+/month starting price and member-based tiering.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Customer support communities$q$, $q$SaaS companies deflect support tickets by hosting Q&A and knowledge base content in a branded community.$q$, $q$SaaS support and customer success teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Product feedback hubs$q$, $q$Product teams collect and prioritize feature requests and feedback through discussion boards and polls.$q$, $q$Product management teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Branded customer events$q$, $q$Companies run virtual events and webinars inside their community using the events app.$q$, $q$Customer marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Starter$q$, $q$$399/month$q$, $q$monthly ($4,788/year annual)$q$, NULL, $q$["Up to 10,000 members","5 collaborators","Q&A, Discussion, Events, Polls apps","Custom domain","Basic analytics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Growth$q$, $q$$1,500/month$q$, $q$monthly ($18,000/year annual)$q$, NULL, $q$["Up to 25,000 members","10 collaborators","Ask AI & federated search","Branding removal","API/webhooks & OAuth2","Advanced analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$Premium$q$, $q$Custom (contact sales)$q$, $q$annual$q$, NULL, $q$["Up to 100,000 members","20 collaborators","SAML SSO","Audit log","99.9% SLA","Dedicated CSM"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bettermode is a white-labeled customer community platform founded in 2018 in Toronto, Canada (originally launched as Tribe before rebranding). It's built for B2B SaaS and product companies that want a fully branded space for customer discussions, Q&A, product feedback, and events, hosted on their own domain rather than a third-party-branded forum.$q$, $q$The platform is positioned at the mid-market to enterprise end of the community-software category, with pricing and features (SAML, audit logs, SLA) aimed at companies treating community as a strategic support and engagement channel.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Design Studio gives full control over layout, color, and typography so the community matches the parent product's branding, hosted on a custom domain. A pre-built app library (Q&A, discussion boards, event calendars, polls, knowledge base) can be composed into different 'spaces' for support, feedback, or general discussion.$q$, $q$Higher tiers add Ask AI (AI-assisted answers and search within community content) and federated search, plus API/webhooks, OAuth2, and — at the enterprise tier — SAML SSO and audit logs for compliance-sensitive buyers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Bettermode has no free plan; it starts at $399/month for up to 10,000 members and scales to $1,500/month for 25,000 members with AI search and API access, with a custom-quoted Premium tier above that for up to 100,000 members and enterprise compliance needs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('64b1d1ff-2ba3-4f6d-b072-c5d804fa6ab3', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$File storage & sync$q$, $q$Self-hosted file storage with symlink-based sharing and desktop/mobile sync clients.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Calendar & contacts$q$, $q$CalDAV and CardDAV support via Radicale integration for calendar and contact syncing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Notes & photos$q$, $q$Built-in notes app and a photo gallery for personal media.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$News reader$q$, $q$A lightweight RSS/news reading feature.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Expense tracking (Envelopes)$q$, $q$A simple built-in tool for tracking personal expenses.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Low resource usage$q$, $q$Runs in under 50 MB of RAM, suitable for minimal VPS plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Docker deployment$q$, $q$Straightforward self-hosted setup via Docker.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Very lightweight compared to Nextcloud, runs on minimal/cheap VPS hardware$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Fully open-source (AGPL-3.0) with no licensing cost$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Covers the core personal-cloud use cases (files, calendar, contacts, notes, photos) without bloat$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Modern, actively maintained tech stack (Deno, Fresh, TypeScript)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Much smaller app ecosystem than Nextcloud (no office suite, no video calls, few third-party apps)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Maintained primarily by a single developer, which is a bus-factor risk for long-term support$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Requires self-hosting knowledge; there is no official managed SaaS plan from bewCloud itself$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Newer project (started 2024) with a smaller community and less battle-testing than established alternatives$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Is bewCloud free?$q$, $q$Yes, bewCloud is free, open-source software (AGPL-3.0) that you self-host; there is no software licensing fee.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$How is bewCloud different from Nextcloud?$q$, $q$bewCloud focuses on a narrower core feature set (files, calendar, contacts, notes, photos) and is built to use far less memory and be simpler to deploy than Nextcloud's PHP-based, app-heavy architecture.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$What do I need to run bewCloud?$q$, $q$You need a server or VPS capable of running Docker; bewCloud is designed to run comfortably in under 50 MB of RAM, so even small/cheap VPS plans work.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Does bewCloud support calendar and contact syncing?$q$, $q$Yes, it supports CalDAV and CardDAV via integration with Radicale for calendar and contact synchronization.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Who maintains bewCloud?$q$, $q$bewCloud is created and primarily maintained by developer Bruno Bernardino, with community contributions on GitHub and sponsorship support from the NLnet Foundation.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Personal cloud self-hosting$q$, $q$Individuals replace commercial cloud storage with a self-hosted, lightweight alternative on their own VPS.$q$, $q$Privacy-conscious individuals and hobbyist self-hosters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$Low-resource server deployments$q$, $q$Users on minimal VPS hardware run a full personal cloud stack without needing to upgrade server resources for Nextcloud.$q$, $q$Budget-conscious self-hosters$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$bewCloud is an open-source, self-hosted personal cloud application created by developer Bruno Bernardino starting in early 2024, built explicitly as a lighter, simpler alternative to Nextcloud and ownCloud. It is written in TypeScript on the Deno runtime using the Fresh framework and is designed to run in under 50 MB of RAM.$q$, $q$The project is released under the AGPL-3.0 license, is developed in the open on GitHub, and has received sponsorship support from the NLnet Foundation, which funds open, privacy-respecting internet infrastructure projects.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$bewCloud covers files, notes, photos, calendar, contacts (via CalDAV/CardDAV through Radicale), a news/RSS reader, and a simple expense-tracking module called Envelopes. File sharing works via symlinks, and desktop and mobile sync clients keep files in sync across devices.$q$, $q$Because it targets a narrower feature set than Nextcloud, it deliberately skips heavier apps like built-in office document editing or video calling, trading breadth for a much smaller resource footprint and simpler deployment via Docker.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$bewCloud itself is free and open-source software with no licensing fee — users self-host it on their own server or a low-cost VPS. The project is funded through GitHub Sponsors and one-time donations rather than a SaaS subscription, and several VPS providers offer one-click bewCloud deployment templates at their standard hosting rates.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b9f2a9ff-f6e9-415b-8ffe-221f389239e2', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Live audio/video/screen sharing$q$, $q$Real-time conferencing built for classroom-style sessions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Multi-user whiteboard$q$, $q$Collaborative whiteboard with annotation tools for presenters and participants.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Breakout rooms$q$, $q$Split a session into smaller group discussions and bring participants back together.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Shared notes & polling$q$, $q$Real-time collaborative notes and live polls for engagement.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Presentation annotation$q$, $q$Upload PDF/Office slide decks and annotate them live during a session.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Session recording$q$, $q$Record classes for on-demand playback, supporting asynchronous learning.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$LMS integration$q$, $q$Deep integration with Moodle and other LMS platforms to launch sessions from course pages.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Free and open-source under LGPL, with no per-user licensing cost for self-hosted deployments$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Purpose-built for teaching, with features general meeting tools lack (breakout rooms, annotation, shared notes)$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$First-party integration with Moodle and support for other major LMS platforms$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Long track record, originating in 2007 with an active open-source community$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Self-hosting requires server infrastructure and ongoing maintenance/upgrades$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$No official unified SaaS pricing; costs depend on chosen managed-hosting provider$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Less polished for general business/corporate meeting use compared to Zoom or Teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Feature set and reliability can vary between third-party hosting providers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Is BigBlueButton free to use?$q$, $q$The core software is free and open-source under the LGPL license. Costs come from self-hosting infrastructure or from optional third-party managed hosting, which typically starts around $149/month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Who created BigBlueButton?$q$, $q$It originated in 2007 at Carleton University in Ottawa, Canada, and was open-sourced in 2009 by Richard Alam, Denis Zgonjanin, and Fred Dixon, who also founded Blindside Networks.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Does BigBlueButton integrate with Moodle?$q$, $q$Yes, Moodle offers a dedicated first-party BigBlueButton activity module, and the platform also integrates with Sakai, Canvas, and other LMS systems.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Can BigBlueButton sessions be recorded?$q$, $q$Yes, sessions can be recorded and made available for on-demand playback.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Is BigBlueButton meant for business meetings or education?$q$, $q$It's purpose-built for online education and virtual classrooms, with features like breakout rooms and slide annotation, rather than general corporate meetings.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$University and school online classes$q$, $q$Institutions self-host BigBlueButton, often via Moodle, to run live, recorded classroom sessions.$q$, $q$Universities, schools, and online education providers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Corporate and nonprofit training$q$, $q$Training organizations use breakout rooms and shared notes to run interactive workshops.$q$, $q$Training providers and nonprofits$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$Budget-constrained institutions$q$, $q$Schools and organizations avoid per-seat licensing costs of commercial video platforms by self-hosting.$q$, $q$Cost-sensitive educational institutions$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$BigBlueButton is a free, open-source virtual classroom platform that began in 2007 at Carleton University in Ottawa, Canada, and was open-sourced in 2009 by its creators, who also founded Blindside Networks to provide paid hosting and support. The project is now overseen by BigBlueButton Inc., a membership-based organization that elects a board to guide development.$q$, $q$Unlike general-purpose video conferencing tools, BigBlueButton is designed specifically for teaching: it prioritizes features like presentation annotation, breakout rooms, and shared notes over generic meeting features.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform provides real-time audio, video, and screen sharing alongside a multi-user whiteboard, public/private chat, shared notes, live polling, and breakout rooms. Presenters can upload and annotate slide decks, and sessions can be recorded for on-demand playback.$q$, $q$Its deepest integrations are with open-source Learning Management Systems — especially Moodle, which offers a dedicated BigBlueButton activity module — plus Sakai, Canvas, and others, letting instructors start a live class session directly from a course page.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core BigBlueButton software is free under the LGPL license, with no vendor licensing fee for self-hosting. Organizations either run and maintain their own servers or pay third-party managed hosting providers, which typically start around $149/month for hosting plus added branding, API, and support services.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6128d24-7ad0-4f60-87ac-6b8a21ef5c99', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Double-entry bookkeeping$q$, $q$Full sales/purchase invoicing, estimates, and general ledger accounting.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Financial reporting suite$q$, $q$Balance sheet, profit & loss, cash flow, journal, and AR/AP aging reports.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Inventory management$q$, $q$Track stock levels, costs, and inventory-related expenses.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Bank synchronization$q$, $q$Connect bank accounts and cards with automatic transaction categorization for reconciliation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Multi-currency support$q$, $q$Real-time exchange rate conversion for international transactions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Self-hosting (open source)$q$, $q$Run the AGPL-licensed codebase on your own infrastructure for free with unlimited users.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Multi-branch/warehouse tracking$q$, $q$Track transactions and stock across multiple locations on higher cloud tiers.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Free, unlimited self-hosting option for teams wanting full data ownership$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Significantly cheaper cloud tiers than comparable QuickBooks/Xero plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Covers a genuinely complete double-entry accounting workflow, not just invoicing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Open-source codebase allows customization and community auditing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Smaller integration ecosystem than established players like QuickBooks or Xero$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Self-hosting requires technical setup and ongoing server maintenance$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$No built-in tax filing or professional bookkeeper network$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Smaller company/team than incumbent accounting vendors, which may affect long-term support depth$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Is Bigcapital free?$q$, $q$Yes, the self-hosted, open-source version is free with unlimited users and transactions. A paid Bigcapital Cloud option is also available starting around $20/month for those who don't want to self-host.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$What license does Bigcapital use?$q$, $q$Bigcapital is released under the AGPL-3.0 open-source license.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Can Bigcapital replace QuickBooks or Xero?$q$, $q$For core bookkeeping, invoicing, inventory, and reporting needs it's designed as a direct alternative, though it has a smaller integration ecosystem and no built-in tax filing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Does Bigcapital support multiple currencies?$q$, $q$Yes, it supports multi-currency transactions with real-time exchange rate conversion.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$How much does Bigcapital Cloud cost?$q$, $q$Cloud plans range from roughly $20/month (Capital Basic) to $60/month (Capital Big), with a discount for annual billing.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Self-hosted bookkeeping for SMBs$q$, $q$Technically capable small businesses self-host Bigcapital for free to keep full control of financial data.$q$, $q$Small and medium businesses with in-house technical resources$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Affordable cloud accounting$q$, $q$Businesses that want managed hosting choose a Bigcapital Cloud tier as a lower-cost alternative to QuickBooks or Xero.$q$, $q$Cost-conscious small businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Inventory-heavy operations$q$, $q$Businesses tracking stock across multiple branches use inventory and multi-warehouse features on higher tiers.$q$, $q$Retail and wholesale SMBs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Capital Basic$q$, $q$$20/month$q$, $q$monthly (annual discount available)$q$, NULL, $q$["Unlimited sales invoices & estimates","Bank connections","Basic GST/VAT reports","Unlimited user seats"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Capital Essential$q$, $q$$40/month$q$, $q$monthly (annual discount available)$q$, NULL, $q$["Purchase invoicing","Multi-currency transactions","Inventory tracking","Advanced financial/inventory reports"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Capital Plus$q$, $q$$55/month$q$, $q$monthly (annual discount available)$q$, NULL, $q$["Custom user roles","Vendor credits","Budgeting & cost-center analysis"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$Capital Big$q$, $q$$60/month$q$, $q$monthly (annual discount available)$q$, NULL, $q$["Multiple branches","Multi-warehouse support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bigcapital is an open-source accounting and inventory management platform created by developer Ahmed Bouhuolia as an alternative to proprietary tools like QuickBooks, Xero, and Wave. It is released under the AGPL-3.0 license and developed openly on GitHub, and can be run either as free self-hosted software or as a paid hosted 'Bigcapital Cloud' product.$q$, $q$The platform targets small and medium businesses that want full double-entry bookkeeping, inventory tracking, and financial reporting without the licensing cost — or, for self-hosters, without the data-ownership tradeoffs — of larger proprietary accounting suites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core accounting features include sales and purchase invoicing, estimates, and a full suite of financial reports (balance sheet, P&L, cash flow, general ledger, journal, AR/AP aging). Inventory tracking covers stock levels, costs, and related expenses, while bank synchronization automatically categorizes transactions to simplify reconciliation.$q$, $q$Multi-currency support with real-time exchange rate conversion, custom user roles, vendor credits, and multi-branch/warehouse tracking are available on higher cloud tiers, alongside the option to self-host the entire platform for free with unlimited users and transactions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Self-hosting Bigcapital's open-source code is free with no user or transaction limits. For businesses that prefer a managed option, Bigcapital Cloud offers four tiers — Capital Basic, Essential, Plus, and Big — ranging from roughly $20 to $60 per month, with a discount for annual billing and unlimited user seats on every tier.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b0ef7337-a5e2-4799-a976-3b354b927eaf', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
