INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$No transaction fees$q$, $q$No added transaction fee on any plan, regardless of payment gateway used.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Headless commerce APIs$q$, $q$GraphQL and REST APIs for decoupling the storefront frontend from BigCommerce's backend.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Multi-storefront management$q$, $q$Run multiple branded stores from a single BigCommerce backend.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Multi-channel selling$q$, $q$Native integrations to sell on Amazon, eBay, Walmart, Facebook, Instagram, and Google.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$B2B Edition$q$, $q$Dedicated wholesale features including custom pricing, quoting, and buyer account management.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$App marketplace$q$, $q$Extend store functionality with third-party apps across marketing, shipping, and operations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Stencil theme system$q$, $q$Customizable storefront themes and a page builder for store design.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$No transaction fees on any plan, regardless of payment processor$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Strong headless/API flexibility for developers building custom storefronts$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Native B2B functionality without needing a separate platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Built-in multi-channel selling across major marketplaces and social platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$GMV-based plan tiers mean fast-growing stores can be pushed into higher-cost tiers automatically$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Steeper learning curve than simpler platforms for non-technical merchants$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Enterprise-level pricing is not public and requires a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Theme and app ecosystem is smaller than Shopify's$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Does BigCommerce charge transaction fees?$q$, $q$No, BigCommerce does not charge additional transaction fees on any plan, regardless of which payment gateway a merchant uses.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$How is BigCommerce pricing determined?$q$, $q$Plans are tiered primarily by a store's trailing-twelve-month gross merchandise value (GMV); as sales grow past a plan's threshold, the merchant is prompted to upgrade to the next tier.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Does BigCommerce support headless commerce?$q$, $q$Yes, it offers GraphQL and REST APIs that let developers build fully custom, decoupled storefronts on top of the BigCommerce backend.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Is BigCommerce good for B2B selling?$q$, $q$Yes, its B2B Edition adds wholesale pricing, quoting, and business buyer account management not present in every competing platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Where is BigCommerce headquartered?$q$, $q$BigCommerce was founded in Sydney, Australia in 2009 and is now headquartered in Austin, Texas.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Scaling mid-market ecommerce$q$, $q$Merchants outgrowing simpler platforms move to BigCommerce for API flexibility and multi-channel selling as revenue grows.$q$, $q$Mid-market to enterprise online retailers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Headless storefront builds$q$, $q$Development teams use BigCommerce's APIs to build fully custom frontends decoupled from the hosted backend.$q$, $q$Ecommerce developers and agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$B2B and wholesale selling$q$, $q$Businesses selling to other businesses use the B2B Edition for custom pricing, quoting, and buyer accounts.$q$, $q$B2B and wholesale sellers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Core$q$, $q$$39/month$q$, $q$monthly$q$, NULL, $q$["For stores up to ~$30K annual sales","Core ecommerce features","Standard support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Growth$q$, $q$$105/month$q$, $q$monthly$q$, NULL, $q$["For stores scaling toward ~$100K annual sales","Advanced reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Scale$q$, $q$$399/month$q$, $q$monthly$q$, NULL, $q$["For stores around $1M annual sales","Advanced feature set"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Performance$q$, $q$From $1,499/month$q$, $q$annual$q$, NULL, $q$["For stores over $1M annual sales","Premium support and features"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$annual$q$, NULL, $q$["Custom SLAs, support, and feature configuration for the largest merchants"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$BigCommerce is a publicly traded (NASDAQ: BIGC) SaaS ecommerce platform, originally founded in Sydney, Australia in 2009 by Eddie Machaalani and Mitchell Harper, and now headquartered in Austin, Texas with roughly 750-800 employees. It's a direct competitor to Shopify and Adobe Commerce, built around an 'open SaaS' model that combines fully hosted infrastructure with more backend and API flexibility than typical closed SaaS platforms.$q$, $q$The platform is aimed primarily at mid-market to enterprise merchants and B2B sellers, with pricing tiers structured around a store's actual sales volume rather than feature bundles alone.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$BigCommerce supports headless commerce via GraphQL/REST APIs, multi-storefront management from a single backend, and native multi-channel selling into Amazon, eBay, Walmart, Facebook, Instagram, and Google. A dedicated B2B Edition adds wholesale pricing, quoting, and buyer management for business-to-business sellers.$q$, $q$Unlike some competitors, BigCommerce charges no transaction fees on any plan regardless of payment gateway, and its app marketplace and Stencil theme system let merchants extend and customize storefronts without switching platforms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$BigCommerce's four public plans — Core, Growth, Scale, and Performance — are gated by a store's trailing-twelve-month GMV rather than purely by feature set, with automatic upgrade prompts as a store's sales grow past a plan's threshold. Enterprise pricing above Performance is custom-quoted for the largest merchants.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
