INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$No-download browser webinars$q$, $q$Attendees join live and on-demand sessions directly in the browser, no app install required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$HD broadcast studio$q$, $q$Live streaming with support for multiple simultaneous webcams, scaling up to 64 on top tiers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Multiple webinar formats$q$, $q$Live, on-demand/evergreen, simulive, and automated 24/7 webinar channels.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Virtual & hybrid events$q$, $q$Breakout rooms, co-browsing, and ticketing/payments for larger virtual or hybrid events.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Social simulcasting$q$, $q$Simultaneous streaming to Facebook Live and YouTube Live.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$CRM & marketing integrations$q$, $q$Connects with CRM/marketing automation platforms, plus API and Zapier access.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Enterprise white-labeling$q$, $q$Custom branded domains, SSO/MFA, live translation/captioning, and a mobile SDK on top tiers.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$No software download required for attendees, lowering the barrier to join$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Supports a wide range of webinar formats, including evergreen and simulive for scaling content$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Handles very large events (up to 500,000 attendees on the top tier)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Deep white-labeling and enterprise security options (SSO, MFA, custom domains) at the top tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$No public self-serve pricing; every tier requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$5% transaction fee applies to paid ticketed events$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Advanced features like API access and breakout rooms are locked behind Enterprise tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Entry-level Basic tier caps webcams and host licenses fairly low compared to Enterprise$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$How much does BigMarker cost?$q$, $q$BigMarker does not publish self-serve pricing; all plans (Basic, Enterprise, Enterprise+) require contacting sales for a custom quote based on attendee volume and features needed.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Do attendees need to download software to join a BigMarker webinar?$q$, $q$No, BigMarker is browser-based and does not require attendees to download an app or plugin.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Does BigMarker support pre-recorded (evergreen) webinars?$q$, $q$Yes, it supports on-demand/evergreen webinars that replay automatically, plus simulive sessions with a live host monitoring chat over a pre-recorded video.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Can BigMarker handle large virtual events?$q$, $q$Yes, its top Enterprise+ tier supports events with up to 500,000 live attendees, along with white-labeled domains and live translation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Does BigMarker charge fees on paid events?$q$, $q$Yes, BigMarker takes a 5% transaction fee on ticketed/paid events, covering payment processing costs.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Lead-generation webinars$q$, $q$Marketing teams run live and evergreen webinars with registration pages and CRM integration to generate leads.$q$, $q$Marketing and demand-generation teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Corporate training and enablement$q$, $q$Training teams use recurring or automated webinar channels to deliver consistent onboarding and enablement content.$q$, $q$L&D and enablement teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Large virtual and hybrid conferences$q$, $q$Event organizers run large-scale virtual or hybrid conferences using breakout rooms, ticketing, and white-labeled branding.$q$, $q$Event organizers and conference producers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Basic$q$, $q$Custom (contact sales)$q$, $q$annual$q$, NULL, $q$["Up to 1,000 live attendees","1 host license","Up to 9 webcams","Live and on-demand webinars","Facebook & YouTube Live streaming"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$annual$q$, NULL, $q$["Up to 10,000 live attendees","4 host licenses","Up to 64 webcams","Virtual events, simulive, evergreen","Ticketing & payments","Breakout rooms","API & Zapier access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$Enterprise+$q$, $q$Custom (contact sales)$q$, $q$annual$q$, NULL, $q$["Up to 500,000 live attendees","6 host licenses","White-labeled domains","Live captioning & translation","SSO and MFA","Mobile SDK"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$BigMarker is a webinar and virtual events platform founded in 2010 and headquartered in Chicago, Illinois. It was designed to run entirely in the browser with no software download required for attendees, competing with tools like Zoom Webinars, ON24, and GoTo Webinar on ease of access for larger, often public-facing audiences.$q$, $q$The platform supports multiple webinar formats — live, on-demand/evergreen, simulive, and automated 24/7 channels — making it a fit for both one-off events and always-on lead-generation content.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$A built-in broadcast studio delivers HD video/audio with support for up to 64 simultaneous webcams on top tiers, plus simultaneous streaming to Facebook Live and YouTube Live. Engagement tools include chat, polls, Q&A, handouts, and post-event surveys, alongside customizable registration pages and automated email campaigns.$q$, $q$Higher tiers unlock virtual/hybrid event features like breakout rooms and co-browsing, ticketing with payment collection, CRM/marketing automation integrations, API and Zapier access, and — at the top tier — white-labeled domains, live translation/captioning, SSO/MFA, and a mobile SDK.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2958e078-5211-4d10-8a25-a1936a3d292c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$BigMarker does not publish self-serve pricing; its Basic, Enterprise, and Enterprise+ tiers are all quote-based depending on attendee caps, host licenses, and integration/white-label needs. Paid ticketed events additionally carry a 5% transaction fee.$q$]::text[], 2);
