-- Enrichment marathon batch: Better Proposals, Better Stack, Bettermode, bewCloud, BigBlueButton, Bigcapital, BigCommerce, BigMarker

-- ── Better Proposals ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Better Proposals is UK-based online proposal software that lets sales teams and agencies design, send, e-sign, and get paid on client proposals in minutes.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$19/month$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Better Proposals: Pricing, Features & Review$q$, seo_title),
  seo_meta_description = COALESCE($q$Better Proposals is proposal software with e-signatures, in-document payments, and 250+ templates. Compare pricing plans, features, pros, cons and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Better Proposals is a bootstrapped, UK-headquartered (London) SaaS company founded by Adam Hempenstall, with the product launching publicly in 2015. It builds web-based proposal, contract, and quote software aimed at freelancers, agencies, and B2B sales teams who want to replace Word or InDesign documents with fast, trackable, web-hosted proposals. Documents are built from a library of 250+ professionally designed templates covering categories such as web design, marketing, consulting, and SaaS sales, and can be customized with a drag-and-drop-style editor, embedded videos, and interactive pricing tables that let prospects choose add-ons before signing. Every proposal is legally binding once signed, using a built-in electronic signature tool, and can accept payment at the moment of signature through native Stripe, PayPal, and GoCardless integrations, so a deal can move from 'sent' to 'signed and paid' without leaving the platform. Senders get real-time notifications and analytics showing when a document is opened, how long each page is viewed, and when it is signed, which is used for follow-up timing and forecasting. A shared content library stores reusable text blocks, case studies, and pricing tables so teams keep consistent messaging across proposals. Better Proposals integrates with roughly 50 external tools, including HubSpot, Salesforce, Pipedrive, Zapier, and payment processors, with deeper CRM and API/Zapier access reserved for higher-tier plans. Pricing is per-user and tiered into three plans: Starter (around $19/month billed monthly, cheaper billed annually) capped at 1 user and 10 sent documents per month; Premium (around $29/month) with unlimited users, 50 documents per month, a custom domain, CRM integrations, and API/Zapier access; and Enterprise (around $49/month) with unlimited documents, content locking, simultaneous multi-user editing, inline commenting, and manager approval workflows. An optional 'Nudge' add-on automates follow-up reminders for a per-user fee, and custom-designed templates can be purchased as a one-time service. The company has never raised venture capital, positioning itself as an independent, profitable, founder-led business, which it uses as a selling point around long-term stability and customer-focused support. Better Proposals differentiates itself from generic e-signature tools (like DocuSign) and from general proposal tools (like PandaDoc or Qwilr) by focusing narrowly on sales proposals with sales-specific analytics, rather than trying to be a broad document-workflow platform. It is commonly used by web and marketing agencies, freelance consultants, and B2B sales teams that send a moderate, predictable volume of proposals each month and want a faster close cycle with less design effort than manually formatted documents.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '95c9d0a5-64da-46ca-b8b7-a7245a366020';

