-- ── Better Stack ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Better Stack is a Prague-based observability platform combining uptime monitoring, log/trace management, and incident/on-call management in one product.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Prague, Czech Republic$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Better Stack: Uptime, Logs & Incident Monitoring$q$, seo_title),
  seo_meta_description = COALESCE($q$Better Stack combines uptime monitoring, log management, and incident response in one platform. Compare pricing, features, pros, cons and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Better Stack is an observability and incident-response platform founded in 2021 by CEO Juraj Masar, headquartered in Prague, Czech Republic, with a team in the roughly 11-50 employee range. It positions itself as a modern, developer-friendly, lower-cost alternative to legacy observability vendors like Datadog, marketing itself explicitly around being cheaper at scale while keeping setup fast. The product bundles three previously separate categories into one platform: uptime monitoring, log and trace management, and incident/on-call management with status pages. The uptime monitoring module checks websites, APIs, ping, SSL certificates, domain expiration, and protocols like POP3, IMAP, SMTP, and DNS from multiple global locations, with checks as frequent as every 3 minutes on the free tier, and supports Slack, email, SMS, and phone call alerts. The logs and traces module ingests structured logs, metrics, and traces from any source, lets teams transform data using Vector Remap Language (VRL), and query it via a drag-and-drop UI, SQL, or PromQL, aiming to replace tools like Datadog, Grafana, or the ELK stack for many teams. The incident management module includes on-call scheduling, escalation policies, incident timelines, Slack-based workflows, and AI-generated post-mortem drafts, and connects directly to the uptime and logging modules so an alert can trigger a paged on-call rotation automatically. Status pages (public or private) can be created and customized to communicate uptime and incidents to customers. Better Stack's pricing is usage- and role-based rather than a single flat per-seat price. There is a genuinely free tier covering personal or small projects: 10 monitors and heartbeats, 1 status page, Slack/email alerts, 100K exceptions/month, 5K session replays, and 3 GB of log/trace/event retention for 3 days. Paid usage starts around $29-34/month for a 'Responder' role that adds uptime alerting plus telemetry access, with additional monitors, status pages, and advanced incident workflows priced as add-ons (e.g., $9/responder/month for advanced workflows, roughly $25/month for 50 more monitors). Telemetry (logs/traces/metrics) is sold in bundles named Nano, Micro, Mega, and Tera, ranging from roughly $30/month up to $1,750/month depending on data volume and retention, with lower rates for annual billing. This granular, consumption-based pricing lets very small teams operate almost entirely on the free tier while larger teams pay primarily for the data volume and responder seats they actually use, which is the core of Better Stack's cost-saving pitch versus flat-rate legacy monitoring and logging vendors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7ff22411-f622-417d-9bda-6ec2bdfd971c';

