-- ── bewCloud ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$bewCloud is a lightweight, open-source self-hosted alternative to Nextcloud, offering file storage, calendar, contacts, notes, and photos in under 50 MB of RAM.$q$, short_description),
  pricing_model = COALESCE($q$Free (open-source, self-hosted)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2024, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$bewCloud: Simple Self-Hosted Nextcloud Alternative$q$, seo_title),
  seo_meta_description = COALESCE($q$bewCloud is an open-source, lightweight Nextcloud/ownCloud alternative built with Deno. See features, self-hosting requirements, pros, cons and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$bewCloud is an open-source personal cloud application created by developer Bruno Bernardino, who began the project in early 2024 as a simpler, lower-overhead alternative to Nextcloud and ownCloud. The motivation, as described by the creator, was frustration with Nextcloud's heavy resource requirements and PHP-based complexity, especially for people running personal instances on small, cheap virtual private servers. bewCloud is built with TypeScript on the Deno runtime using the Fresh web framework, and is designed to run in under 50 MB of RAM, making it viable on minimal VPS plans where Nextcloud would struggle. The project is released under the AGPL-3.0 license and hosted on GitHub under the bewcloud organization, where it has accumulated several hundred stars and community contributions; it has also received sponsorship support from the NLnet Foundation, a European organization that funds open internet and privacy-respecting software projects. Functionally, bewCloud covers the core use cases that most self-hosters actually use Nextcloud for, rather than replicating its entire app ecosystem: file storage and sharing (using a symlink-based sharing model), a notes app, a photo gallery, a calendar and contacts system built on CalDAV/CardDAV via Radicale integration, a lightweight news/RSS reader, and a simple expense-tracking feature called 'Envelopes.' It supports Docker-based deployment for straightforward self-hosting, and desktop/mobile sync clients exist for keeping files in sync across devices. Because it is fully open-source and self-hosted, there is no vendor-run SaaS subscription required to use bewCloud — anyone can download and run it for free on their own server or a low-cost VPS from a provider like Hostinger, DigitalOcean, or Cloudzy, several of which offer one-click bewCloud deployment templates. The project sustains itself through GitHub Sponsors (starting around $100+ tiers) and one-time donations rather than software licensing fees, which is typical for solo-maintainer open-source infrastructure projects. bewCloud is best understood as a narrower, faster, and lighter-weight alternative to Nextcloud for privacy-conscious individuals and small teams who want to self-host their files, calendar, and contacts without operating a resource-hungry PHP application stack, rather than as a full groupware or office-suite replacement — it intentionally does not attempt to match Nextcloud's much larger app marketplace (no built-in office document editing, video calls, or the dozens of third-party apps Nextcloud supports).$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b9f2a9ff-f6e9-415b-8ffe-221f389239e2';

