-- ── BigBlueButton ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BigBlueButton is a free, open-source virtual classroom platform offering video, whiteboards, breakout rooms, and polling, built for online education and LMS integration.$q$, short_description),
  pricing_model = COALESCE($q$Free (open-source, self-hosted)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Ottawa, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Portuguese$q$, $q$Chinese$q$]::text[],
  seo_title = COALESCE($q$BigBlueButton: Open-Source Virtual Classroom Software$q$, seo_title),
  seo_meta_description = COALESCE($q$BigBlueButton is free, open-source video conferencing for online education, with whiteboards, breakout rooms, and LMS integration. See features and hosting.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BigBlueButton is an open-source web conferencing system purpose-built for virtual classrooms and online education, rather than general business meetings. It originated in 2007 at Carleton University in Ottawa, Canada, as a project (initially called Blindside) written by Richard Alam under Carleton's Technology Innovation Management program; the code was open-sourced in 2009 by Alam along with Denis Zgonjanin and Fred Dixon, who also formed Blindside Networks, a company offering paid hosting and support for the project. Governance later moved toward BigBlueButton Inc., a membership-based organization (functioning similarly to a nonprofit foundation, though Canadian law didn't allow the 'Foundation' name) that elects a board of directors overseeing the project's direction, while Blindside Networks continues to describe itself as the project's originator and a managed-hosting provider. The software itself is released under the GNU Lesser General Public License (LGPL), meaning anyone can self-host, modify, and redistribute it at no licensing cost. Core features include real-time audio, video, and screen sharing; a multi-user whiteboard with annotation tools; public and private chat; shared notes; live polling; emoji reactions; and breakout rooms for small-group work, all built around the needs of a classroom rather than a boardroom. Presenters can upload slide decks (including PDF and Office formats) for live annotation, and sessions can be recorded for on-demand playback, which is heavily used for asynchronous or hybrid learning. BigBlueButton is most commonly deployed as the video-conferencing backend for open-source Learning Management Systems, with especially deep integration into Moodle (which offers a first-party BigBlueButton activity module), as well as Sakai, Canvas, Jenzabar, and other LMS platforms, letting instructors launch a live class session directly from a course page. Because the core software is free and self-hosted, there's no official BigBlueButton pricing page in the traditional SaaS sense — organizations either run their own servers (incurring only infrastructure costs) or purchase managed hosting from third-party providers, several of which start around $149/month and add features like custom branding, API access, and dedicated support on top of the open-source core. The interface has been translated into dozens of languages through community-driven crowdsourced translation (via Transifex), reflecting its global use in universities and school systems, particularly in regions where licensing costs for commercial platforms like Zoom or Microsoft Teams are prohibitive. BigBlueButton is best suited to educational institutions, training organizations, and anyone building an LMS-integrated live-classroom experience, rather than as a general Zoom or Google Meet replacement for corporate meetings.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c6128d24-7ad0-4f60-87ac-6b8a21ef5c99';

