-- ── BigCommerce ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BigCommerce is a NASDAQ-listed, Austin-based SaaS ecommerce platform for building and scaling online stores, with no transaction fees on any plan.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$39/month$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$750+ employees$q$, company_size),
  headquarters = COALESCE($q$Austin, Texas, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BigCommerce: Pricing Plans, Features & Review 2026$q$, seo_title),
  seo_meta_description = COALESCE($q$BigCommerce is a SaaS ecommerce platform with no transaction fees. Compare Core, Growth, Scale, and Enterprise pricing, features, pros, cons and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BigCommerce is a publicly traded (NASDAQ: BIGC) software-as-a-service ecommerce platform originally founded in Sydney, Australia in 2009 by Eddie Machaalani and Mitchell Harper, who met in an online chatroom in 2003. The company later relocated its headquarters to Austin, Texas, where it remains based today with additional offices globally, and employs roughly 750-800 people as of 2026. BigCommerce competes primarily with Shopify and Adobe Commerce (Magento) as a hosted ecommerce platform that handles storefront hosting, checkout, and backend order/inventory management, distinguishing itself with an 'open SaaS' approach: merchants get a fully hosted, PCI-compliant platform but retain more backend and API flexibility than typical closed SaaS competitors, including headless commerce support (decoupling the frontend from BigCommerce's backend using its GraphQL/REST APIs) and multi-storefront capability for running several branded stores from one backend. A key differentiator versus Shopify is that BigCommerce charges no additional transaction fees on any plan regardless of payment gateway used, whereas some competitors charge extra unless using their proprietary payment processor. The platform includes native multi-channel selling into Amazon, eBay, Walmart, Facebook, Instagram, and Google, a page-builder/Stencil theme system for storefront design, a B2B Edition for wholesale and business buyers, and an app marketplace for extending functionality. Pricing is tiered by trailing-twelve-month gross merchandise value (GMV) rather than a fixed feature-based tier alone: Core (around $39/month) targets new businesses with up to roughly $30K in annual online sales; Growth (around $105/month) targets businesses scaling toward $100K; Scale (around $399/month) targets businesses around $1M in annual sales; and Performance (starting around $1,499/month, billed annually) targets high-volume businesses exceeding $1M in sales, with fully custom Enterprise pricing available above that for the largest merchants. As a store's sales volume crosses a plan's GMV threshold, BigCommerce automatically notifies and upgrades the merchant to the next tier to maintain platform performance and support levels appropriate to their scale. BigCommerce is generally chosen by mid-market and larger ecommerce businesses, B2B sellers, and merchants who have outgrown simpler platforms or need deeper API/headless flexibility, multi-storefront management, or B2B-specific functionality that lighter platforms don't offer natively.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c3103af2-b89a-4cb2-ac57-83030df19efa';

